    type Item;
    fn next(&'a mut self) -> Option<Self::Item>;
}

struct WindowIter<'a> {
    data: &'a [u8],
    pos: usize,
    size: usize,
}

impl<'a> LendingIterator<'a> for WindowIter<'a> {
    type Item = &'a [u8];
    fn next(&'a mut self) -> Option<&'a [u8]> {
