// With GATs (stable since Rust 1.65): the Item lifetime is per-call, not per-trait
trait LendingIterator {
    type Item<'a> where Self: 'a;
    fn next(&mut self) -> Option<Self::Item<'_>>;
}

struct WindowIter<'data> {
    data: &'data [u8],
    pos: usize,
    size: usize,
}

impl<'data> LendingIterator for WindowIter<'data> {
    type Item<'a> = &'a [u8] where Self: 'a;
    fn next(&mut self) -> Option<&[u8]> {
        if self.pos + self.size > self.data.len() {
            return None;
        }
        let window = &self.data[self.pos..self.pos + self.size];
        self.pos += 1;
        Some(window)
    }
}

fn print_windows(iter: &mut impl LendingIterator) {
    while let Some(w) = iter.next() {
        println!("{:?}", w);
    }
}

fn main() {
    let data = [1u8, 2, 3, 4, 5];
    let mut iter = WindowIter { data: &data, pos: 0, size: 3 };
    print_windows(&mut iter);
}

