use std::fmt::Display;

trait Printable {
    type Repr<'a>: Display where Self: 'a;
    fn repr(&self) -> Self::Repr<'_>;
}

struct Wrapper(i32);

impl Printable for Wrapper {
    type Repr<'a> = &'a i32 where Self: 'a;
    fn repr(&self) -> &i32 {
        &self.0
    }
}

fn print_all<T: Printable>(items: &[T])
where
    for<'a> T::Repr<'a>: Display,  // explicitly bring the bound into scope
{
    for item in items {
        let r = item.repr();
        println!("{}", r);
    }
}

fn main() {
    let ws = vec![Wrapper(1), Wrapper(2)];
    print_all(&ws);
}

